// STOCK-ALERT: 재고 분석 + 메시지 생성
// MakeShop 상품 API 응답 파싱 후 임계값 기반 분류

const THRESHOLD = 5; // 재고 임계값
const rawResp = $input.first().json;

// --- API 응답 검증 ---
if (rawResp.error || rawResp.return_code === '9000' || rawResp.return_code === '9018') {
  var errCode = rawResp.return_code || rawResp.error || 'UNKNOWN';
  return [{ json: {
    hasAlert: true,
    isError: true,
    message: '\u26a0\ufe0f <b>STOCK-ALERT API 오류</b>\n\n'
      + 'MakeShop 상품 API 호출 실패\n'
      + '오류 코드: ' + errCode + '\n'
      + '시각: ' + new Date().toLocaleString('ko-KR', {timeZone: 'Asia/Seoul'})
  } }];
}

// --- 상품 데이터 추출 ---
// MakeShop API: list가 객체(키=상품번호) 또는 배열일 수 있음
var rawList = rawResp.list || rawResp.datas || rawResp;
var products;
if (Array.isArray(rawList)) {
  products = rawList;
} else if (rawList && typeof rawList === 'object') {
  products = Object.values(rawList);
} else {
  products = [];
}

// 상품 수 안전 검증 (10개 미만이면 API 이상)
if (products.length < 10) {
  return [{ json: {
    hasAlert: true,
    isError: true,
    message: '\u26a0\ufe0f <b>STOCK-ALERT 데이터 이상</b>\n\n'
      + '조회된 상품: ' + products.length + '개 (최소 10개 미만)\n'
      + 'API 응답이 비정상일 수 있습니다.\n'
      + '시각: ' + new Date().toLocaleString('ko-KR', {timeZone: 'Asia/Seoul'})
  } }];
}

// --- 재고 분류 ---
var critical = []; // 재고 0 (품절)
var warning = [];  // 재고 1~THRESHOLD
var totalCount = products.length;

for (var i = 0; i < products.length; i++) {
  var p = products[i];
  var stockVal = parseInt(p.stock || p.stock_count || '0', 10);
  var isSoldOut = (p.sold_out === 'Y' || p.soldout === 'Y');
  var pName = p.product_name || p.brandname || '이름없음';
  var pNum = p.uid || p.branduid || p.productnum || '';
  var price = parseInt(p.sellprice || '0', 10);

  // 이미 품절 처리된 상품은 critical에 포함
  if (isSoldOut || stockVal <= 0) {
    critical.push({
      name: pName,
      num: pNum,
      stock: stockVal,
      price: price,
      soldOut: isSoldOut
    });
  } else if (stockVal <= THRESHOLD) {
    warning.push({
      name: pName,
      num: pNum,
      stock: stockVal,
      price: price
    });
  }
}

// 알림 대상 없으면 종료
if (critical.length === 0 && warning.length === 0) {
  return [{ json: {
    hasAlert: false,
    message: '',
    criticalCount: 0,
    warningCount: 0,
    totalCount: totalCount
  } }];
}

// --- 텔레그램 메시지 포맷팅 ---
var now = new Date();
var kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
var dateStr = String(kst.getMonth() + 1).padStart(2, '0') + '/' + String(kst.getDate()).padStart(2, '0');
var fmt = function(n) { return n.toLocaleString('ko-KR'); };
var truncName = function(name, maxLen) {
  if (name.length > maxLen) return name.slice(0, maxLen) + '..';
  return name;
};

var msg = '\ud83d\udce6 <b>재고 부족 알림</b> (' + dateStr + ')\n';
msg += '\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n';

// 품절 (critical)
if (critical.length > 0) {
  msg += '\ud83d\udd34 <b>품절 (0개)</b>: ' + critical.length + '건\n';
  var showCritical = critical.slice(0, 15);
  for (var ci = 0; ci < showCritical.length; ci++) {
    var c = showCritical[ci];
    msg += '  \u2022 ' + truncName(c.name, 25);
    if (c.num) msg += ' (' + c.num + ')';
    msg += '\n';
  }
  if (critical.length > 15) {
    msg += '  ... 외 ' + (critical.length - 15) + '건\n';
  }
  msg += '\n';
}

// 부족 (warning)
if (warning.length > 0) {
  // 재고 적은 순 정렬
  warning.sort(function(a, b) { return a.stock - b.stock; });
  msg += '\ud83d\udfe1 <b>부족 (' + THRESHOLD + '개 이하)</b>: ' + warning.length + '건\n';
  var showWarning = warning.slice(0, 15);
  for (var wi = 0; wi < showWarning.length; wi++) {
    var w = showWarning[wi];
    msg += '  \u2022 ' + truncName(w.name, 25) + ' - 남은 ' + w.stock + '개\n';
  }
  if (warning.length > 15) {
    msg += '  ... 외 ' + (warning.length - 15) + '건\n';
  }
  msg += '\n';
}

msg += '\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n';
msg += '총 상품: ' + fmt(totalCount) + '개 중 ' + (critical.length + warning.length) + '건 알림\n';
msg += '\ud83e\udd16 자동 생성 by n8n STOCK-ALERT';

return [{ json: {
  hasAlert: true,
  isError: false,
  message: msg,
  criticalCount: critical.length,
  warningCount: warning.length,
  totalCount: totalCount,
  criticalProducts: critical,
  warningProducts: warning
} }];

// 정상 - 알림 대상 없음 (로깅용)
return [{ json: {
  status: 'ok',
  message: 'STOCK-ALERT: 재고 이상 없음',
  timestamp: new Date().toISOString()
} }];
